module RefModule(CLK, EN, TE, DATA, Q);input CLK, EN, TE;
  input [31:0] DATA;
  output reg [31:0] Q;

  wire gated_clk;

  wire __EN_tmp = (EN && !TE);
  assign gated_clk = __EN_tmp ? CLK : 1'b0;

  always @(posedge gated_clk) begin
    if (EN && !TE) begin
      Q <= DATA;
    end
  end

endmodule
